import{_ as d,o as e,c as o,ag as c}from"./chunks/framework.D54qew5K.js";const A=JSON.parse('{"title":"配置参考","description":"","frontmatter":{},"headers":[],"relativePath":"reference/config.md","filePath":"reference/config.md","lastUpdated":1774527358000}'),a={name:"reference/config.md"};function r(h,t,_,i,l,E){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="配置参考" tabindex="-1">配置参考 <a class="header-anchor" href="#配置参考" aria-label="Permalink to &quot;配置参考&quot;">​</a></h1><p>本文档列出 AeroLoongClaw 所有环境变量及其默认值。完整列表来源：<code>src/config.ts</code>。</p><h2 id="环境变量读取优先级" tabindex="-1">环境变量读取优先级 <a class="header-anchor" href="#环境变量读取优先级" aria-label="Permalink to &quot;环境变量读取优先级&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>`.env` 文件 &lt; process.env &lt; 默认值</span></span></code></pre></div><p>:::note <code>.env</code> 文件中的值会覆盖代码中的默认值，但 <code>process.env</code> 中的值优先级最高。 :::</p><h2 id="ai-模型配置" tabindex="-1">AI 模型配置 <a class="header-anchor" href="#ai-模型配置" aria-label="Permalink to &quot;AI 模型配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>OPENCODE_MODEL</code></td><td><code>minimax/MiniMax-M2.7</code></td><td>用于 OpenCode 任务的语言模型，格式为 <code>provider/model</code></td></tr><tr><td><code>MODEL</code></td><td>—</td><td><code>OPENCODE_MODEL</code> 的别名，兼容旧版本</td></tr><tr><td><code>ASSISTANT_NAME</code></td><td><code>Andy</code></td><td>助手名字，用户在聊天中用来 @ 助手的名字</td></tr><tr><td><code>ASSISTANT_HAS_OWN_NUMBER</code></td><td><code>false</code></td><td>助手是否拥有专用电话号码。<code>true</code> 时私聊不需要 @ 触发</td></tr></tbody></table><h2 id="provider-api-keys" tabindex="-1">Provider API Keys <a class="header-anchor" href="#provider-api-keys" aria-label="Permalink to &quot;Provider API Keys&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>ANTHROPIC_API_KEY</code></td><td>Anthropic API 密钥</td></tr><tr><td><code>ANTHROPIC_BASE_URL</code></td><td>自定义 Anthropic API 端点（用于代理）</td></tr><tr><td><code>OPENAI_API_KEY</code></td><td>OpenAI API 密钥</td></tr><tr><td><code>GOOGLE_API_KEY</code> / <code>GEMINI_API_KEY</code></td><td>Google API 密钥</td></tr><tr><td><code>MINIMAX_API_KEY</code></td><td>MiniMax API 密钥（Anthropic 兼容端点）</td></tr></tbody></table><h2 id="企业微信配置" tabindex="-1">企业微信配置 <a class="header-anchor" href="#企业微信配置" aria-label="Permalink to &quot;企业微信配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>WECOM_ENABLED</code></td><td><code>false</code></td><td>是否启用企业微信渠道</td></tr><tr><td><code>WECOM_BOT_ID</code></td><td>—</td><td>企业微信智能机器人 Bot ID</td></tr><tr><td><code>WECOM_BOT_SECRET</code></td><td>—</td><td>企业微信智能机器人 Bot Secret</td></tr><tr><td><code>WECOM_WEBSOCKET_URL</code></td><td><code>wss://openws.work.weixin.qq.com</code></td><td>企业微信长连接地址</td></tr><tr><td><code>WECOM_FOUNDER_USER_ID</code></td><td>—</td><td>企业微信创始人用户 ID，用于首次部署引导</td></tr></tbody></table><h2 id="web-ui-配置" tabindex="-1">Web UI 配置 <a class="header-anchor" href="#web-ui-配置" aria-label="Permalink to &quot;Web UI 配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>WEB_UI_ENABLED</code></td><td><code>true</code></td><td>是否启用本地 Web 测试聊天界面</td></tr><tr><td><code>WEB_UI_HOST</code></td><td><code>127.0.0.1</code></td><td>Web UI 绑定主机地址</td></tr><tr><td><code>WEB_UI_PORT</code></td><td><code>3100</code></td><td>Web UI 监听端口</td></tr><tr><td><code>WEB_UI_TOKEN</code></td><td>—</td><td>Web UI 访问令牌，留空则自动生成</td></tr></tbody></table><h2 id="http-api-网关配置" tabindex="-1">HTTP API 网关配置 <a class="header-anchor" href="#http-api-网关配置" aria-label="Permalink to &quot;HTTP API 网关配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>API_HOST</code></td><td><code>127.0.0.1</code></td><td>HTTP API 网关绑定地址</td></tr><tr><td><code>API_PORT</code></td><td><code>3200</code></td><td>HTTP API 网关监听端口</td></tr><tr><td><code>API_TOKEN</code></td><td>—</td><td>HTTP API Bearer token，留空则不启动 API 服务器</td></tr><tr><td><code>METRICS_TOKEN</code></td><td>—</td><td><code>/metrics</code> 端点的独立 Bearer token</td></tr></tbody></table><h2 id="容器配置" tabindex="-1">容器配置 <a class="header-anchor" href="#容器配置" aria-label="Permalink to &quot;容器配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>CONTAINER_IMAGE</code></td><td><code>aeroloongclaw-agent:latest</code></td><td>Docker 镜像名称和标签</td></tr><tr><td><code>CONTAINER_TIMEOUT</code></td><td><code>1800000</code></td><td>容器执行任务超时时间（毫秒，30 分钟）</td></tr><tr><td><code>CONTAINER_MAX_OUTPUT_SIZE</code></td><td><code>10485760</code></td><td>容器输出最大大小（字节，10MB）</td></tr><tr><td><code>IDLE_TIMEOUT</code></td><td><code>1800000</code></td><td>容器空闲超时时间（毫秒，30 分钟）</td></tr><tr><td><code>MAX_CONCURRENT_CONTAINERS</code></td><td><code>5</code></td><td>同时运行的最大容器数量</td></tr><tr><td><code>PER_GROUP_MAX_PARALLEL_TASKS</code></td><td><code>3</code></td><td>单个群组允许并行执行的 isolated 计划任务数量上限</td></tr><tr><td><code>PER_GROUP_MAX_PARALLEL_CHAT_RUNS</code></td><td><code>1</code></td><td>单个群组允许并行执行的聊天任务数量上限</td></tr></tbody></table><h2 id="媒体存储配置" tabindex="-1">媒体存储配置 <a class="header-anchor" href="#媒体存储配置" aria-label="Permalink to &quot;媒体存储配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>MEDIA_MAX_FILE_SIZE</code></td><td><code>52428800</code></td><td>单个媒体文件最大大小（字节，50MB）</td></tr><tr><td><code>MEDIA_MAX_GROUP_STORAGE</code></td><td><code>524288000</code></td><td>单个群组媒体目录最大总容量（字节，500MB）</td></tr><tr><td><code>MEDIA_CLEANUP_MAX_AGE_DAYS</code></td><td><code>7</code></td><td>媒体文件保留天数</td></tr><tr><td><code>MEDIA_CLEANUP_INTERVAL</code></td><td><code>21600000</code></td><td>媒体清理任务轮询间隔（毫秒，6 小时）</td></tr></tbody></table><h2 id="opencode-功能开关" tabindex="-1">OpenCode 功能开关 <a class="header-anchor" href="#opencode-功能开关" aria-label="Permalink to &quot;OpenCode 功能开关&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>OPENCODE_EVENT_BRIDGE_ENABLED</code></td><td><code>true</code></td><td>启用事件桥接</td></tr><tr><td><code>OPENCODE_PERMISSION_BRIDGE_ENABLED</code></td><td><code>true</code></td><td>启用权限桥接</td></tr><tr><td><code>OPENCODE_NATIVE_ASSETS_ENABLED</code></td><td><code>true</code></td><td>启用原生资产</td></tr><tr><td><code>OPENCODE_NATIVE_AGENTS_ENABLED</code></td><td><code>true</code></td><td>启用原生 agent 流水线</td></tr></tbody></table><h2 id="其他配置" tabindex="-1">其他配置 <a class="header-anchor" href="#其他配置" aria-label="Permalink to &quot;其他配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>TZ</code></td><td>系统时区</td><td>用于计划任务的时区</td></tr><tr><td><code>CHAT_QUEUE_ACK_ENABLED</code></td><td><code>false</code></td><td>是否启用聊天队列确认机制</td></tr></tbody></table><h2 id="路径配置-可通过环境变量覆盖" tabindex="-1">路径配置（可通过环境变量覆盖） <a class="header-anchor" href="#路径配置-可通过环境变量覆盖" aria-label="Permalink to &quot;路径配置（可通过环境变量覆盖）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>AEROLOONGCLAW_ENV_FILE</code></td><td><code>.env</code> 文件路径</td></tr><tr><td><code>AEROLOONGCLAW_STORE_DIR</code></td><td>持久化数据存储目录</td></tr><tr><td><code>AEROLOONGCLAW_DATA_DIR</code></td><td>通用数据目录</td></tr><tr><td><code>AEROLOONGCLAW_GROUPS_DIR</code></td><td>群组工作区目录</td></tr><tr><td><code>AEROLOONGCLAW_CUSTOM_SKILLS_DIR</code></td><td>自定义 skills 目录</td></tr><tr><td><code>AEROLOONGCLAW_LOGS_DIR</code></td><td>日志目录</td></tr><tr><td><code>AEROLOONGCLAW_MOUNT_ALLOWLIST_PATH</code></td><td>挂载白名单 JSON 文件路径</td></tr><tr><td><code>AEROLOONGCLAW_SENDER_ALLOWLIST_PATH</code></td><td>发送者白名单 JSON 文件路径</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Release 安装模式下，这些路径默认位于 <code>/etc/aeroloongclaw/</code> 和 <code>/var/lib/aeroloongclaw/</code>。</p></div><h2 id="内部常量-不可配置" tabindex="-1">内部常量（不可配置） <a class="header-anchor" href="#内部常量-不可配置" aria-label="Permalink to &quot;内部常量（不可配置）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>常量</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td><code>POLL_INTERVAL</code></td><td><code>2000</code></td><td>主事件循环轮询间隔（毫秒）</td></tr><tr><td><code>SCHEDULER_POLL_INTERVAL</code></td><td><code>60000</code></td><td>任务调度器轮询间隔（毫秒）</td></tr><tr><td><code>IPC_POLL_INTERVAL</code></td><td><code>1000</code></td><td>IPC 轮询间隔（毫秒）</td></tr><tr><td><code>CONTAINER_MEDIA_PREFIX</code></td><td><code>/workspace/group/media</code></td><td>容器内媒体目录路径</td></tr></tbody></table>',28)])])}const b=d(a,[["render",r]]);export{A as __pageData,b as default};
